-- Seed Tổ SX Lai Khê — lô, phần cạo, nhân sự, phân công mặc định
-- Chạy theo thứ tự:
--   1. schema-field-workforce.sql
--   2. views-field-workforce.sql
--   3. file này
--   (hoặc chỉ bổ sung lô/PC: seed-lots-sections-supplement.sql … supplement-3.sql)
--
-- Nguồn: danh sách công nhân Tổ SX Lai Khê (58 dòng; bỏ dòng Trạm Lai Khê)

CREATE EXTENSION IF NOT EXISTS "uuid-ossp";

-- Đội / Tổ
   '{"department_id":"dl-3","code":"LK","location":"Lai Khê","station":"Trạm Lai Khê"}')
ON CONFLICT (id) DO UPDATE SET
  name = EXCLUDED.name,
  department = EXCLUDED.department,
  metadata = EXCLUDED.metadata;

-- Nhóm trong đội
ON CONFLICT (id) DO UPDATE SET
  name = EXCLUDED.name,
  team_id = EXCLUDED.team_id;

-- Lô (ID LÔ = khóa chính bảng rubber_lots.id)
ON CONFLICT (id) DO UPDATE SET
  lot_code = EXCLUDED.lot_code,
  squad = EXCLUDED.squad,
  metadata = EXCLUDED.metadata;

-- Phần cạo: UNIQUE (lot_id, section_no); section_code = ID_LÔ|PC|số
ON CONFLICT (id) DO UPDATE SET
  section_code = EXCLUDED.section_code,
  lot_id = EXCLUDED.lot_id,
  lot_name = EXCLUDED.lot_name,
  section_no = EXCLUDED.section_no,
  team_id = EXCLUDED.team_id;

